## 二、方案一：自己实现 TODO 工具

参考 `examples/quickstart/todoagent/main.go` 的实现：

```go
package main

import (
    "context"
    "fmt"

    "github.com/cloudwego/eino/components/tool"
    "github.com/cloudwego/eino/components/tool/utils"
    "github.com/cloudwego/eino/schema"
)

// 1️⃣ 定义 TODO 数据结构
type TodoItem struct {
    ID        string  `json:"id"`
    Content   string  `json:"content"`
    Done      bool    `json:"done"`
    StartedAt *int64  `json:"started_at,omitempty"`
    Deadline  *int64  `json:"deadline,omitempty"`
}

// 内存存储（可替换为数据库）
var todoStore = make(map[string]*TodoItem)

// 2️⃣ 创建 AddTodo 工具
func createAddTodoTool() tool.InvokableTool {
    info := &schema.ToolInfo{
        Name: "add_todo",
        Desc: "Add a new todo item",
        ParamsOneOf: schema.NewParamsOneOfByParams(map[string]*schema.ParameterInfo{
            "content": {
                Desc:     "The content of the todo item",
                Type:     schema.String,
                Required: true,
            },
            "deadline": {
                Desc: "The deadline (unix timestamp)",
                Type: schema.Integer,
            },
        }),
    }

    return utils.NewTool(info, func(ctx context.Context, params *struct {
        Content  string `json:"content"`
        Deadline *int64 `json:"deadline,omitempty"`
    }) (string, error) {
        id := generateID()
        todoStore[id] = &TodoItem{
            ID:       id,
            Content:  params.Content,
            Done:     false,
            Deadline: params.Deadline,
        }
        return fmt.Sprintf(`{"success": true, "id": "%s"}`, id), nil
    })
}

// 3️⃣ 创建 ListTodo 工具
func createListTodoTool() tool.InvokableTool {
    return utils.NewTool(
        &schema.ToolInfo{
            Name: "list_todos",
            Desc: "List all todo items",
            ParamsOneOf: schema.NewParamsOneOfByParams(map[string]*schema.ParameterInfo{
                "finished": {
                    Desc: "Filter by completion status",
                    Type: schema.Boolean,
                },
            }),
        },
        func(ctx context.Context, params *struct {
            Finished *bool `json:"finished,omitempty"`
        }) (string, error) {
            // 返回 JSON 格式的任务列表
            return toJSON(todoStore), nil
        },
    )
}

// 4️⃣ 创建 UpdateTodo 工具
func createUpdateTodoTool() tool.InvokableTool {
    return utils.NewTool(
        &schema.ToolInfo{
            Name: "update_todo",
            Desc: "Update a todo item",
            ParamsOneOf: schema.NewParamsOneOfByParams(map[string]*schema.ParameterInfo{
                "id":      {Desc: "Todo ID", Type: schema.String, Required: true},
                "content": {Desc: "New content", Type: schema.String},
                "done":    {Desc: "Completion status", Type: schema.Boolean},
            }),
        },
        func(ctx context.Context, params *struct {
            ID      string  `json:"id"`
            Content *string `json:"content,omitempty"`
            Done    *bool   `json:"done,omitempty"`
        }) (string, error) {
            todo, ok := todoStore[params.ID]
            if !ok {
                return `{"success": false, "error": "not found"}`, nil
            }
            if params.Content != nil {
                todo.Content = *params.Content
            }
            if params.Done != nil {
                todo.Done = *params.Done
            }
            return `{"success": true}`, nil
        },
    )
}
```

